1	/**
2	 * Mixer audio graph engine.
3	 * Per-track channel strips -> master bus -> brickwall limiter -> destination.
4	 *
5	 * INV-2: Non-bypassable DynamicsCompressorNode as brickwall limiter
6	 * (threshold=-1dBFS, ratio=20:1, knee=0, attack=0.001s)
7	 */
8	
9	import type { ChannelStrip, MasterBus, MixerEngine } from "./types";
10	
11	function clamp(v: number, min: number, max: number): number {
12	  return Math.min(max, Math.max(min, v));
13	}
14	
15	/**
16	 * Quadratic fader taper: attempt to model a real mixing console fader.
17	 * Maps linear 0..2 -> gain curve.
18	 * 0 -> 0 (silence), 1 -> 1 (unity), 2 -> 2 (boost)
19	 */
20	function faderTaper(linear: number): number {
21	  if (linear <= 0) return 0;
22	  if (linear <= 1) {
23	    // Attempt log curve: x^2 gives reasonable taper for 0..1
24	    return linear * linear;
25	  }
26	  // Above unity: linear interpolation from 1..2
27	  return 1 + (linear - 1);
28	}
29	
30	function createMasterBus(ctx: AudioContext): MasterBus {
31	  const inputGain = ctx.createGain();
32	  const faderGain = ctx.createGain();
33	  const limiter = ctx.createDynamicsCompressor();
34	  const analyser = ctx.createAnalyser();
35	
36	  // INV-2: Brickwall limiter settings
37	  limiter.threshold.value = -1;
38	  limiter.ratio.value = 20;
39	  limiter.knee.value = 0;
40	  limiter.attack.value = 0.001;
41	  limiter.release.value = 0.01;
42	
43	  // Chain: inputGain -> faderGain -> limiter -> analyser -> destination
44	  inputGain.connect(faderGain);
45	  faderGain.connect(limiter);
46	  limiter.connect(analyser);
47	  analyser.connect(ctx.destination);
48	
49	  return { inputGain, faderGain, limiter, analyser };
50	}
51	
52	function createChannelStrip(
53	  ctx: AudioContext,
54	  trackId: string,
55	  masterInput: GainNode,
56	): ChannelStrip {
57	  const inputGain = ctx.createGain();
58	  const faderGain = ctx.createGain();
59	  const panner = ctx.createStereoPanner();
60	  const muteGain = ctx.createGain();
61	  const analyser = ctx.createAnalyser();
62	
63	  // Chain: inputGain -> faderGain -> panner -> muteGain -> analyser -> master input
64	  inputGain.connect(faderGain);
65	  faderGain.connect(panner);
66	  panner.connect(muteGain);
67	  muteGain.connect(analyser);
68	  analyser.connect(masterInput);
69	
70	  return {
71	    trackId,
72	    inputGain,
73	    inserts: [],
74	    faderGain,
75	    panner,
76	    muteGain,
77	    analyser,
78	    muted: false,
79	    solo: false,
80	    soloIsolate: false,
81	  };
82	}
83	
84	export function createMixerEngine(ctx: AudioContext): MixerEngine {
85	  const master = createMasterBus(ctx);
86	  const strips = new Map<string, ChannelStrip>();
87	  let savedMasterLevel = 1;
88	
89	  function applyMuteState(strip: ChannelStrip): void {
90	    const hasSolo = [...strips.values()].some((s) => s.solo);
91	
92	    if (strip.muted) {
93	      strip.muteGain.gain.value = 0;
94	      return;
95	    }
96	
97	    if (hasSolo) {
98	      if (strip.solo || strip.soloIsolate) {
99	        strip.muteGain.gain.value = 1;
100	      } else {
101	        strip.muteGain.gain.value = 0;
102	      }
103	    } else {
104	      strip.muteGain.gain.value = 1;
105	    }
106	  }
107	
108	  const engine: MixerEngine = {
109	    getOrCreateStrip(trackId: string): ChannelStrip {
110	      const existing = strips.get(trackId);
111	      if (existing) return existing;
112	
113	      const strip = createChannelStrip(ctx, trackId, master.inputGain);
114	      strips.set(trackId, strip);
115	      return strip;
116	    },
117	
118	    removeStrip(trackId: string): void {
119	      const strip = strips.get(trackId);
120	      if (!strip) return;
121	
122	      strip.inputGain.disconnect();
123	      strip.faderGain.disconnect();
124	      strip.panner.disconnect();
125	      strip.muteGain.disconnect();
126	      strip.analyser.disconnect();
127	      strips.delete(trackId);
128	    },
129	
130	    getStrip(trackId: string): ChannelStrip | undefined {
131	      return strips.get(trackId);
132	    },
133	
134	    getAllStrips(): readonly ChannelStrip[] {
135	      return [...strips.values()];
136	    },
137	
138	    getMaster(): MasterBus {
139	      return master;
140	    },
141	
142	    setFaderLevel(trackId: string, level: number): void {
143	      const strip = strips.get(trackId);
144	      if (!strip) return;
145	      const clamped = clamp(level, 0, 2);
146	      strip.faderGain.gain.value = faderTaper(clamped);
147	    },
148	
149	    setPan(trackId: string, pan: number): void {
150	      const strip = strips.get(trackId);
151	      if (!strip) return;
152	      strip.panner.pan.value = clamp(pan, -1, 1);
153	    },
154	
155	    setMute(trackId: string, muted: boolean): void {
156	      const strip = strips.get(trackId);
157	      if (!strip) return;
158	      strip.muted = muted;
159	      applyMuteState(strip);
160	    },
161	
162	    setSolo(trackId: string, solo: boolean): void {
163	      const strip = strips.get(trackId);
164	      if (!strip) return;
165	      strip.solo = solo;
166	      engine.updateSoloState();
167	    },
168	
169	    setSoloIsolate(trackId: string, enabled: boolean): void {
170	      const strip = strips.get(trackId);
171	      if (!strip) return;
172	      strip.soloIsolate = enabled;
173	      engine.updateSoloState();
174	    },
175	
176	    updateSoloState(): void {
177	      for (const strip of strips.values()) {
178	        applyMuteState(strip);
179	      }
180	    },
181	
182	    setMasterLevel(level: number): void {
183	      savedMasterLevel = clamp(level, 0, 2);
184	      master.faderGain.gain.value = savedMasterLevel;
185	    },
186	
187	    getTrackInput(trackId: string): AudioNode {
188	      return engine.getOrCreateStrip(trackId).inputGain;
189	    },
190	
191	    emergencyMute(): void {
192	      master.faderGain.gain.value = 0;
193	    },
194	
195	    releaseEmergencyMute(): void {
196	      master.faderGain.gain.value = savedMasterLevel;
197	    },
198	
199	    dispose(): void {
200	      for (const strip of strips.values()) {
201	        strip.inputGain.disconnect();
202	        strip.faderGain.disconnect();
203	        strip.panner.disconnect();
204	        strip.muteGain.disconnect();
205	        strip.analyser.disconnect();
206	      }
207	      strips.clear();
208	      master.inputGain.disconnect();
209	      master.faderGain.disconnect();
210	      master.limiter.disconnect();
211	      master.analyser.disconnect();
212	    },
213	  };
214	
215	  return engine;
216	}
