1	import { useRef, useEffect, useCallback } from "react";
2	import { tokens } from "../tokens/tokens";
3	
4	type RotaryKnobProps = {
5	  value: number;
6	  min: number;
7	  max: number;
8	  step?: number;
9	  onChange: (value: number) => void;
10	  label: string;
11	  size?: number;
12	};
13	
14	const START_ANGLE = 0.75 * Math.PI;
15	const END_ANGLE = 2.25 * Math.PI;
16	const ARC_RANGE = END_ANGLE - START_ANGLE;
17	const DRAG_SENSITIVITY = 200;
18	
19	function clamp(v: number, min: number, max: number): number {
20	  return Math.min(max, Math.max(min, v));
21	}
22	
23	function snapToStep(raw: number, step: number): number {
24	  return Math.round(raw / step) * step;
25	}
26	
27	function drawKnob(
28	  ctx: CanvasRenderingContext2D,
29	  size: number,
30	  ratio: number,
31	): void {
32	  const cx = size / 2;
33	  const cy = size / 2;
34	  const radius = size / 2 - tokens.border.width * 2;
35	
36	  ctx.clearRect(0, 0, size, size);
37	
38	  // Outer circle
39	  ctx.beginPath();
40	  ctx.arc(cx, cy, radius, 0, 2 * Math.PI);
41	  ctx.strokeStyle = tokens.color.gray700;
42	  ctx.lineWidth = tokens.border.width;
43	  ctx.stroke();
44	
45	  // Value arc
46	  const valueAngle = START_ANGLE + ratio * ARC_RANGE;
47	  ctx.beginPath();
48	  ctx.arc(cx, cy, radius, START_ANGLE, valueAngle);
49	  ctx.strokeStyle = tokens.color.blue;
50	  ctx.lineWidth = tokens.border.width + 1;
51	  ctx.lineCap = "round";
52	  ctx.stroke();
53	
54	  // Pointer line from center
55	  const pointerLen = radius * 0.7;
56	  const px = cx + Math.cos(valueAngle) * pointerLen;
57	  const py = cy + Math.sin(valueAngle) * pointerLen;
58	  ctx.beginPath();
59	  ctx.moveTo(cx, cy);
60	  ctx.lineTo(px, py);
61	  ctx.strokeStyle = tokens.color.white;
62	  ctx.lineWidth = tokens.border.width;
63	  ctx.lineCap = "round";
64	  ctx.stroke();
65	}
66	
67	export function RotaryKnob({
68	  value,
69	  min,
70	  max,
71	  step = 1,
72	  onChange,
73	  label,
74	  size = 48,
75	}: RotaryKnobProps): React.JSX.Element {
76	  const canvasRef = useRef<HTMLCanvasElement>(null);
77	  const listenersRef = useRef<AbortController | null>(null);
78	
79	  const ratio = max === min ? 0 : (value - min) / (max - min);
80	
81	  useEffect(() => {
82	    const canvas = canvasRef.current;
83	    if (!canvas) return;
84	    const ctx = canvas.getContext("2d");
85	    if (!ctx) return;
86	    drawKnob(ctx, size, ratio);
87	  }, [value, min, max, size, ratio]);
88	
89	  // Cleanup drag listeners on unmount
90	  useEffect(() => {
91	    return (): void => {
92	      listenersRef.current?.abort();
93	    };
94	  }, []);
95	
96	  const commit = useCallback(
97	    (next: number): void => {
98	      onChange(clamp(snapToStep(next, step), min, max));
99	    },
100	    [onChange, min, max, step],
101	  );
102	
103	  const handleKeyDown = useCallback(
104	    (e: React.KeyboardEvent): void => {
105	      switch (e.key) {
106	        case "ArrowUp":
107	        case "ArrowRight":
108	          e.preventDefault();
109	          commit(value + step);
110	          break;
111	        case "ArrowDown":
112	        case "ArrowLeft":
113	          e.preventDefault();
114	          commit(value - step);
115	          break;
116	        case "PageUp":
117	          e.preventDefault();
118	          commit(value + step * 10);
119	          break;
120	        case "PageDown":
121	          e.preventDefault();
122	          commit(value - step * 10);
123	          break;
124	        case "Home":
125	          e.preventDefault();
126	          commit(min);
127	          break;
128	        case "End":
129	          e.preventDefault();
130	          commit(max);
131	          break;
132	      }
133	    },
134	    [value, step, min, max, commit],
135	  );
136	
137	  const handleMouseDown = useCallback(
138	    (e: React.MouseEvent): void => {
139	      e.preventDefault();
140	      const startY = e.clientY;
141	      const startValue = value;
142	      const range = max - min;
143	
144	      listenersRef.current?.abort();
145	      const controller = new AbortController();
146	      listenersRef.current = controller;
147	
148	      document.addEventListener(
149	        "mousemove",
150	        (moveEvent: MouseEvent) => {
151	          const delta = startY - moveEvent.clientY;
152	          const fraction = delta / DRAG_SENSITIVITY;
153	          commit(startValue + fraction * range);
154	        },
155	        { signal: controller.signal },
156	      );
157	
158	      document.addEventListener(
159	        "mouseup",
160	        () => {
161	          controller.abort();
162	        },
163	        { signal: controller.signal },
164	      );
165	    },
166	    [value, max, min, commit],
167	  );
168	
169	  return (
170	    <div
171	      role="slider"
172	      tabIndex={0}
173	      aria-valuemin={min}
174	      aria-valuemax={max}
175	      aria-valuenow={value}
176	      aria-label={label}
177	      onKeyDown={handleKeyDown}
178	      style={{
179	        display: "inline-flex",
180	        flexDirection: "column",
181	        alignItems: "center",
182	        gap: tokens.space[1],
183	        userSelect: "none",
184	      }}
185	    >
186	      <span
187	        style={{
188	          fontSize: tokens.text.xs,
189	          fontFamily: tokens.font.mono,
190	          color: tokens.color.gray300,
191	        }}
192	      >
193	        {label}
194	      </span>
195	      <canvas
196	        ref={canvasRef}
197	        width={size}
198	        height={size}
199	        onMouseDown={handleMouseDown}
200	        style={{ cursor: "grab" }}
201	      />
202	      <span
203	        style={{
204	          fontSize: tokens.text.xs,
205	          fontFamily: tokens.font.mono,
206	          color: tokens.color.white,
207	        }}
208	      >
209	        {value}
210	      </span>
211	    </div>
212	  );
213	}
