1	import { useCallback, useRef, useEffect } from "react";
2	import styles from "./Fader.module.css";
3	
4	type FaderProps = {
5	  value: number;
6	  min: number;
7	  max: number;
8	  step?: number;
9	  onChange: (value: number) => void;
10	  label: string;
11	  height?: number;
12	};
13	
14	function clamp(val: number, min: number, max: number): number {
15	  return Math.min(max, Math.max(min, val));
16	}
17	
18	export function Fader({
19	  value,
20	  min,
21	  max,
22	  step = 1,
23	  onChange,
24	  label,
25	  height = 128,
26	}: FaderProps): React.JSX.Element {
27	  const trackRef = useRef<HTMLDivElement>(null);
28	  const listenersRef = useRef<AbortController | null>(null);
29	
30	  const fraction = max === min ? 0 : (value - min) / (max - min);
31	
32	  // Cleanup drag listeners on unmount
33	  useEffect(() => {
34	    return (): void => {
35	      listenersRef.current?.abort();
36	    };
37	  }, []);
38	
39	  const handleKeyDown = useCallback(
40	    (e: React.KeyboardEvent): void => {
41	      let next: number | undefined;
42	
43	      switch (e.key) {
44	        case "ArrowUp":
45	          next = clamp(value + step, min, max);
46	          break;
47	        case "ArrowDown":
48	          next = clamp(value - step, min, max);
49	          break;
50	        case "PageUp":
51	          next = clamp(value + step * 10, min, max);
52	          break;
53	        case "PageDown":
54	          next = clamp(value - step * 10, min, max);
55	          break;
56	        case "Home":
57	          next = min;
58	          break;
59	        case "End":
60	          next = max;
61	          break;
62	        default:
63	          return;
64	      }
65	
66	      e.preventDefault();
67	      onChange(next);
68	    },
69	    [value, min, max, step, onChange],
70	  );
71	
72	  const valueFromY = useCallback(
73	    (clientY: number): number => {
74	      const track = trackRef.current;
75	      if (!track) return value;
76	      const rect = track.getBoundingClientRect();
77	      const pxFromBottom = rect.bottom - clientY;
78	      const ratio = pxFromBottom / rect.height;
79	      const raw = min + ratio * (max - min);
80	      return clamp(Math.round(raw / step) * step, min, max);
81	    },
82	    [value, min, max, step],
83	  );
84	
85	  const handleMouseDown = useCallback(
86	    (e: React.MouseEvent): void => {
87	      e.preventDefault();
88	
89	      listenersRef.current?.abort();
90	      const controller = new AbortController();
91	      listenersRef.current = controller;
92	
93	      document.addEventListener(
94	        "mousemove",
95	        (ev: MouseEvent) => {
96	          onChange(valueFromY(ev.clientY));
97	        },
98	        { signal: controller.signal },
99	      );
100	      document.addEventListener(
101	        "mouseup",
102	        () => {
103	          controller.abort();
104	        },
105	        { signal: controller.signal },
106	      );
107	    },
108	    [onChange, valueFromY],
109	  );
110	
111	  return (
112	    <div
113	      className={styles["container"]}
114	      role="slider"
115	      tabIndex={0}
116	      aria-valuemin={min}
117	      aria-valuemax={max}
118	      aria-valuenow={value}
119	      aria-orientation="vertical"
120	      aria-label={label}
121	      onKeyDown={handleKeyDown}
122	    >
123	      <div
124	        ref={trackRef}
125	        className={styles["track"]}
126	        style={{ height: `${String(height)}px` }}
127	      >
128	        <div
129	          className={styles["active"]}
130	          style={{ height: `${String(fraction * 100)}%` }}
131	        />
132	        <div
133	          className={styles["thumb"]}
134	          style={{ bottom: `${String(fraction * 100)}%` }}
135	          onMouseDown={handleMouseDown}
136	        />
137	      </div>
138	      <span className={styles["label"]}>{label}</span>
139	    </div>
140	  );
141	}
