1	/**
2	 * Metering utilities for peak + RMS computation.
3	 * Clip indicator with latching (R-UNW-01).
4	 * Emergency mute on sustained clipping >500ms (R-UNW-05).
5	 *
6	 * NFR-13: High-frequency UI bypasses React -- reads from SharedArrayBuffer via rAF.
7	 */
8	
9	export const CLIP_THRESHOLD = 1.0;
10	export const EMERGENCY_MUTE_MS = 500;
11	
12	export type PeakRms = {
13	  peak: number;
14	  rms: number;
15	};
16	
17	/** Compute peak and RMS from time-domain sample data */
18	export function computePeakAndRms(data: Float32Array): PeakRms {
19	  let peak = 0;
20	  let sumSquares = 0;
21	  const len = data.length;
22	
23	  for (let i = 0; i < len; i++) {
24	    const sample = data[i] ?? 0;
25	    const abs = Math.abs(sample);
26	    if (abs > peak) peak = abs;
27	    sumSquares += sample * sample;
28	  }
29	
30	  const rms = len > 0 ? Math.sqrt(sumSquares / len) : 0;
31	  return { peak, rms };
32	}
33	
34	export type MeterUpdateResult = {
35	  emergencyMute: boolean;
36	};
37	
38	/**
39	 * Per-channel meter state with clip latching and emergency mute tracking.
40	 */
41	export class MeterState {
42	  peak = 0;
43	  rms = 0;
44	  clipping = false;
45	  private clipDurationMs = 0;
46	
47	  clearClip(): void {
48	    this.clipping = false;
49	    this.clipDurationMs = 0;
50	  }
51	}
52	
53	/**
54	 * Update meter state with new peak/rms values.
55	 * @param state - Meter state to update (mutated in place)
56	 * @param peak - Current peak level
57	 * @param rms - Current RMS level
58	 * @param deltaMs - Time since last update in milliseconds
59	 * @returns Whether emergency mute should be triggered
60	 */
61	export function updateMeterState(
62	  state: MeterState,
63	  peak: number,
64	  rms: number,
65	  deltaMs: number,
66	): MeterUpdateResult {
67	  state.peak = peak;
68	  state.rms = rms;
69	
70	  if (peak >= CLIP_THRESHOLD) {
71	    state.clipping = true;
72	    state.clipDurationMs += deltaMs;
73	  } else {
74	    state.clipDurationMs = 0;
75	  }
76	
77	  return {
78	    emergencyMute: state.clipDurationMs >= EMERGENCY_MUTE_MS,
79	  };
80	}

