1	/**
2	 * DFS cycle detection for audio routing graph (INV-1).
3	 * Runs on every routing mutation to prevent feedback loops (R-UNW-05).
4	 * Insert-only topology is acyclic by construction, but this infrastructure
5	 * exists for E13 (Advanced Mixer Routing) with sends and aux buses.
6	 */
7	
8	export class RoutingGraph {
9	  private readonly adjacency = new Map<string, Set<string>>();
10	
11	  addNode(id: string): void {
12	    if (!this.adjacency.has(id)) {
13	      this.adjacency.set(id, new Set());
14	    }
15	  }
16	
17	  removeNode(id: string): void {
18	    this.adjacency.delete(id);
19	    for (const edges of this.adjacency.values()) {
20	      edges.delete(id);
21	    }
22	  }
23	
24	  addEdge(from: string, to: string): void {
25	    this.addNode(from);
26	    this.addNode(to);
27	    const edges = this.adjacency.get(from);
28	    if (edges) edges.add(to);
29	  }
30	
31	  removeEdge(from: string, to: string): void {
32	    this.adjacency.get(from)?.delete(to);
33	  }
34	
35	  getNodes(): readonly string[] {
36	    return [...this.adjacency.keys()];
37	  }
38	
39	  getEdges(from: string): ReadonlySet<string> {
40	    return this.adjacency.get(from) ?? new Set();
41	  }
42	
43	  /** Check if adding edge from->to would create a cycle without actually adding it */
44	  wouldCauseCycle(from: string, to: string): boolean {
45	    // Adding from->to creates a cycle iff there's already a path from to->from
46	    return hasPath(this, to, from);
47	  }
48	}
49	
50	/** Standard DFS cycle detection using three-color marking */
51	export function hasCycle(graph: RoutingGraph): boolean {
52	  const WHITE = 0;
53	  const GRAY = 1;
54	  const BLACK = 2;
55	  const color = new Map<string, number>();
56	
57	  for (const node of graph.getNodes()) {
58	    color.set(node, WHITE);
59	  }
60	
61	  function dfs(node: string): boolean {
62	    color.set(node, GRAY);
63	    for (const neighbor of graph.getEdges(node)) {
64	      const c = color.get(neighbor);
65	      if (c === GRAY) return true; // back edge = cycle
66	      if (c === WHITE && dfs(neighbor)) return true;
67	    }
68	    color.set(node, BLACK);
69	    return false;
70	  }
71	
72	  for (const node of graph.getNodes()) {
73	    if (color.get(node) === WHITE && dfs(node)) {
74	      return true;
75	    }
76	  }
77	
78	  return false;
79	}
80	
81	/** BFS reachability check: is there a path from `start` to `target`? */
82	function hasPath(graph: RoutingGraph, start: string, target: string): boolean {
83	  if (start === target) return true;
84	  const visited = new Set<string>();
85	  const queue = [start];
86	  visited.add(start);
87	
88	  while (queue.length > 0) {
89	    const current = queue.shift();
90	    if (current === undefined) break;
91	    for (const neighbor of graph.getEdges(current)) {
92	      if (neighbor === target) return true;
93	      if (!visited.has(neighbor)) {
94	        visited.add(neighbor);
95	        queue.push(neighbor);
96	      }
97	    }
98	  }
99	
100	  return false;
101	}
