170	    set((state) => {
171	      const fromIndex = state.tracks.findIndex((t) => t.id === id);
172	      if (fromIndex === -1) return state;
173	      const next = [...state.tracks];
174	      const moved = next.splice(fromIndex, 1)[0];
175	      if (moved === undefined) return state;
176	      next.splice(toIndex, 0, moved);
177	      return { tracks: next };
178	    });
179	  },
