245	    if (atTime <= clip.startTime || atTime >= clipEnd) return undefined;
246	
247	    const leftDuration = atTime - clip.startTime;
248	    const rightDuration = clip.duration - leftDuration;
249	    const rightSourceOffset = clip.sourceOffset + leftDuration;
250	
251	    const newId = providedId ?? nextClipId();
252	
253	    const leftClip: ClipModel = { ...clip, duration: leftDuration };
254	    const rightClip: ClipModel = {
255	      ...clip,
256	      id: newId,
257	      startTime: atTime,
258	      sourceOffset: rightSourceOffset,
259	      duration: rightDuration,
260	    };
261	
262	    set((s) => {
263	      const nextClips = { ...s.clips, [id]: leftClip, [newId]: rightClip };
264	      const tracks = s.tracks.map((t) =>
265	        t.id === clip.trackId ? { ...t, clipIds: [...t.clipIds, newId] } : t,
266	      );
267	      return { clips: nextClips, tracks };
268	    });
269	
270	    return newId;
271	  },
