1	import { z } from "zod/v4";
2	import { trackSchema, clipSchema } from "@state/track/index";
3	
4	export const SESSION_VERSION = 1;
5	
6	export const metaSectionSchema = z.object({
7	  name: z.string(),
8	  createdAt: z.number(),
9	  updatedAt: z.number(),
10	});
11	
12	export const transportSectionSchema = z
13	  .object({
14	    bpm: z.number().min(1).max(999),
15	    loopEnabled: z.boolean(),
16	    loopStart: z.number().min(0),
17	    loopEnd: z.number().min(0),
18	  })
19	  .refine((t) => t.loopEnd >= t.loopStart, {
20	    message: "loopEnd must be >= loopStart",
21	  });
22	
23	export const mixerSectionSchema = z.object({
24	  masterVolume: z.number().min(0).max(2),
25	});
26	
27	export const sessionSchema = z.object({
28	  version: z.literal(SESSION_VERSION),
29	  meta: metaSectionSchema,
30	  transport: transportSectionSchema,
31	  tracks: z.array(trackSchema),
32	  clips: z.array(clipSchema),
33	  mixer: mixerSectionSchema,
34	});
35	
36	export type SessionSchema = z.infer<typeof sessionSchema>;
37	
38	export function createDefaultSession(): SessionSchema {
