  { name: "Mid Q", key: "midQ", min: 0.1, max: 18, default: 1.4, step: 0.1, unit: "" },
  { name: "High Freq", key: "highFreq", min: 2000, max: 20000, default: 8000, step: 1, unit: "Hz" },
