  dryGain.gain.value = 0;
  wetGain.gain.value = 1;

  // Parameter storage
  const paramMap = new Map<string, { schema: EffectParameterSchema; value: number }>();
  for (const p of params) {
    paramMap.set(p.key, { schema: p, value: p.default });
  }

  let bypassed = false;
  let mixLevel = 1; // 0 = fully dry, 1 = fully wet

  function applyMix(): void {
    if (bypassed) {
      dryGain.gain.value = 1;
      wetGain.gain.value = 0;
    } else {
      dryGain.gain.value = 1 - mixLevel;
      wetGain.gain.value = mixLevel;
    }
  }

  function setMix(wet: number): void {
    mixLevel = clamp(wet, 0, 1);
    applyMix();
  }

  const instance: EffectInstance = {
    id,
    typeId,
    input,
    output,
    dryGain,
    wetGain,
    bypassed: false,

    getParam(key: string): number {
