      entry.value = clamp(value, entry.schema.min, entry.schema.max);
      applyParam(key, entry.value);
    },

    setBypassed(b: boolean): void {
      bypassed = b;
      instance.bypassed = b;
      applyMix();
    },

    setMix(wet: number): void {
      mixLevel = clamp(wet, 0, 1);
      applyMix();
    },

    dispose(): void {
      input.disconnect();
      output.disconnect();
      dryGain.disconnect();
      wetGain.disconnect();
      effectInput.disconnect();
      effectOutput.disconnect();
    },
  };

  // Initialize all params via applyParam (deferred to after instance creation)
  for (const [key, entry] of paramMap) {
    applyParam(key, entry.value);
  }

  return instance;
}

