1	/**
2	 * Reverb effect using ConvolverNode with generated impulse responses.
3	 * Generates exponentially decaying noise IR at the requested decay time.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const PARAMS: readonly EffectParameterSchema[] = [
10	  { name: "Decay", key: "decay", min: 0.1, max: 10, default: 2, step: 0.1, unit: "s" },
11	  { name: "Pre-Delay", key: "preDelay", min: 0, max: 100, default: 10, step: 1, unit: "ms" },
12	  { name: "Mix", key: "mix", min: 0, max: 100, default: 30, step: 1, unit: "%" },
13	];
14	
15	function generateImpulseResponse(
16	  ctx: AudioContext,
17	  decaySeconds: number,
18	): AudioBuffer {
19	  const sampleRate = ctx.sampleRate;
20	  const length = Math.floor(sampleRate * decaySeconds);
21	  const buffer = ctx.createBuffer(2, length, sampleRate);
22	
23	  for (let ch = 0; ch < 2; ch++) {
24	    const data = buffer.getChannelData(ch);
25	    for (let i = 0; i < length; i++) {
26	      const t = i / sampleRate;
27	      // Exponential decay envelope * white noise
28	      data[i] = (Math.random() * 2 - 1) * Math.exp(-3 * t / decaySeconds);
29	    }
30	  }
31	  return buffer;
32	}
33	
34	export function createReverbFactory(): EffectFactory {
35	  return {
36	    definition: { id: "reverb", name: "Reverb", parameters: PARAMS },
37	    create(ctx, id) {
38	      let convolver: ConvolverNode;
39	      let preDelayNode: DelayNode;
40	
41	      return createBaseEffect({
42	        ctx,
43	        id,
44	        typeId: "reverb",
45	        params: PARAMS,
46	        buildChain(inputNode, outputNode) {
47	          preDelayNode = ctx.createDelay(0.1);
48	          convolver = ctx.createConvolver();
49	          convolver.buffer = generateImpulseResponse(ctx, 2);
50	
51	          inputNode.connect(preDelayNode);
52	          preDelayNode.connect(convolver);
53	          convolver.connect(outputNode);
54	        },
55	        applyParam(key, value, setMix) {
56	          switch (key) {
57	            case "decay":
58	              if (convolver) {
59	                convolver.buffer = generateImpulseResponse(ctx, value);
60	              }
61	              break;
62	            case "preDelay":
63	              if (preDelayNode) {
64	                preDelayNode.delayTime.value = value / 1000;
65	              }
66	              break;
67	            case "mix":
68	              setMix(value / 100);
69	              break;
70	          }
71	        },
72	      });
73	    },
74	  };
75	}
76

1	/**
2	 * Delay effect: simple delay with feedback via DelayNode + GainNode.
3	 * Feedback is clamped to <1.0 to prevent runaway oscillation.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const MAX_FEEDBACK = 0.95;
10	
11	const PARAMS: readonly EffectParameterSchema[] = [
12	  { name: "Time", key: "time", min: 0.01, max: 2, default: 0.3, step: 0.01, unit: "s" },
13	  { name: "Feedback", key: "feedback", min: 0, max: MAX_FEEDBACK, default: 0.4, step: 0.01, unit: "" },
14	  { name: "Mix", key: "mix", min: 0, max: 100, default: 30, step: 1, unit: "%" },
15	];
16	
17	export function createDelayFactory(): EffectFactory {
18	  return {
19	    definition: { id: "delay", name: "Delay", parameters: PARAMS },
20	    create(ctx, id) {
21	      let delayNode: DelayNode;
22	      let feedbackGain: GainNode;
23	
24	      return createBaseEffect({
25	        ctx,
26	        id,
27	        typeId: "delay",
28	        params: PARAMS,
29	        buildChain(inputNode, outputNode) {
30	          delayNode = ctx.createDelay(2);
31	          feedbackGain = ctx.createGain();
32	
33	          delayNode.delayTime.value = 0.3;
34	          feedbackGain.gain.value = 0.4;
35	
36	          inputNode.connect(delayNode);
37	          delayNode.connect(outputNode);
38	          delayNode.connect(feedbackGain);
39	          feedbackGain.connect(delayNode);
40	        },
41	        applyParam(key, value, setMix) {
42	          switch (key) {
43	            case "time":
44	              if (delayNode) {
45	                delayNode.delayTime.value = value;
46	              }
47	              break;
48	            case "feedback":
49	              if (feedbackGain) {
50	                feedbackGain.gain.value = Math.min(value, MAX_FEEDBACK);
51	              }
52	              break;
53	            case "mix":
54	              setMix(value / 100);
55	              break;
56	          }
57	        },
58	      });
59	    },
60	  };
61	}
62

1	/**
2	 * Compressor effect using DynamicsCompressorNode.
3	 * Exposes threshold, ratio, knee, attack, release.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const PARAMS: readonly EffectParameterSchema[] = [
10	  { name: "Threshold", key: "threshold", min: -60, max: 0, default: -24, step: 0.5, unit: "dB" },
11	  { name: "Ratio", key: "ratio", min: 1, max: 20, default: 4, step: 0.5, unit: ":1" },
12	  { name: "Knee", key: "knee", min: 0, max: 40, default: 10, step: 0.5, unit: "dB" },
13	  { name: "Attack", key: "attack", min: 0, max: 1, default: 0.003, step: 0.001, unit: "s" },
14	  { name: "Release", key: "release", min: 0.01, max: 1, default: 0.25, step: 0.01, unit: "s" },
15	];
16	
17	export function createCompressorFactory(): EffectFactory {
18	  return {
19	    definition: { id: "compressor", name: "Compressor", parameters: PARAMS },
20	    create(ctx, id) {
21	      let comp: DynamicsCompressorNode;
22	
23	      const effect = createBaseEffect({
24	        ctx,
25	        id,
26	        typeId: "compressor",
27	        params: PARAMS,
28	        buildChain(inputNode, outputNode) {
29	          comp = ctx.createDynamicsCompressor();
