1	/**
2	 * 3-band parametric EQ using cascaded BiquadFilterNodes.
3	 * Low shelf -> Peaking (mid) -> High shelf.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const PARAMS: readonly EffectParameterSchema[] = [
10	  { name: "Low Freq", key: "lowFreq", min: 20, max: 500, default: 100, step: 1, unit: "Hz" },
11	  { name: "Low Gain", key: "lowGain", min: -24, max: 24, default: 0, step: 0.5, unit: "dB" },
12	  { name: "Mid Freq", key: "midFreq", min: 200, max: 8000, default: 1000, step: 1, unit: "Hz" },
13	  { name: "Mid Gain", key: "midGain", min: -24, max: 24, default: 0, step: 0.5, unit: "dB" },
14	  { name: "Mid Q", key: "midQ", min: 0.1, max: 18, default: 1.4, step: 0.1, unit: "" },
15	  { name: "High Freq", key: "highFreq", min: 2000, max: 20000, default: 8000, step: 1, unit: "Hz" },
16	  { name: "High Gain", key: "highGain", min: -24, max: 24, default: 0, step: 0.5, unit: "dB" },
17	];
18	
19	export function createEqFactory(): EffectFactory {
20	  return {
21	    definition: { id: "eq", name: "Parametric EQ", parameters: PARAMS },
22	    create(ctx, id) {
23	      let lowShelf: BiquadFilterNode;
24	      let mid: BiquadFilterNode;
25	      let highShelf: BiquadFilterNode;
26	
27	      const effect = createBaseEffect({
28	        ctx,
29	        id,
30	        typeId: "eq",
31	        params: PARAMS,
32	        buildChain(inputNode, outputNode) {
33	          lowShelf = ctx.createBiquadFilter();
34	          lowShelf.type = "lowshelf";
35	          lowShelf.frequency.value = 100;
36	          lowShelf.gain.value = 0;
37	
38	          mid = ctx.createBiquadFilter();
39	          mid.type = "peaking";
40	          mid.frequency.value = 1000;
41	          mid.Q.value = 1.4;
42	          mid.gain.value = 0;
43	
44	          highShelf = ctx.createBiquadFilter();
45	          highShelf.type = "highshelf";
46	          highShelf.frequency.value = 8000;
47	          highShelf.gain.value = 0;
48	
49	          // Cascade: input -> low shelf -> mid -> high shelf -> output
50	          inputNode.connect(lowShelf);
51	          lowShelf.connect(mid);
52	          mid.connect(highShelf);
53	          highShelf.connect(outputNode);
54	        },
55	        applyParam(key, value) {
56	          switch (key) {
57	            case "lowFreq":
58	              if (lowShelf) lowShelf.frequency.value = value;
59	              break;
60	            case "lowGain":
61	              if (lowShelf) lowShelf.gain.value = value;
62	              break;
63	            case "midFreq":
64	              if (mid) mid.frequency.value = value;
65	              break;
66	            case "midGain":
67	              if (mid) mid.gain.value = value;
68	              break;
69	            case "midQ":
70	              if (mid) mid.Q.value = value;
71	              break;
72	            case "highFreq":
73	              if (highShelf) highShelf.frequency.value = value;
74	              break;
75	            case "highGain":
76	              if (highShelf) highShelf.gain.value = value;
77	              break;
78	          }
79	        },
80	      });
81	
82	      return effect;
83	    },
84	  };
85	}
