1	/**
2	 * Chorus/Flanger/Phaser effect using modulated delay.
3	 * DelayNode modulated by OscillatorNode LFO.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const PARAMS: readonly EffectParameterSchema[] = [
10	  { name: "Rate", key: "rate", min: 0.1, max: 10, default: 1.5, step: 0.1, unit: "Hz" },
11	  { name: "Depth", key: "depth", min: 0, max: 20, default: 5, step: 0.1, unit: "ms" },
12	  { name: "Mix", key: "mix", min: 0, max: 100, default: 50, step: 1, unit: "%" },
13	];
14	
15	export function createChorusFactory(): EffectFactory {
16	  return {
17	    definition: { id: "chorus", name: "Chorus", parameters: PARAMS },
18	    create(ctx, id) {
19	      let lfo: OscillatorNode;
20	      let lfoGain: GainNode;
21	      let delayNode: DelayNode;
22	
23	      return createBaseEffect({
24	        ctx,
25	        id,
26	        typeId: "chorus",
27	        params: PARAMS,
28	        buildChain(inputNode, outputNode) {
29	          delayNode = ctx.createDelay(0.05);
30	          delayNode.delayTime.value = 0.01;
31	
32	          lfo = ctx.createOscillator();
33	          lfo.type = "sine";
34	          lfo.frequency.value = 1.5;
35	
36	          lfoGain = ctx.createGain();
37	          lfoGain.gain.value = 0.005;
38	
39	          lfo.connect(lfoGain);
40	          lfoGain.connect(delayNode.delayTime as unknown as AudioParam);
41	
42	          inputNode.connect(delayNode);
43	          delayNode.connect(outputNode);
44	
45	          lfo.start();
46	        },
47	        applyParam(key, value, setMix) {
48	          switch (key) {
49	            case "rate":
50	              if (lfo) lfo.frequency.value = value;
51	              break;
52	            case "depth":
53	              if (lfoGain) lfoGain.gain.value = value / 1000;
54	              break;
55	            case "mix":
56	              setMix(value / 100);
57	              break;
58	          }
59	        },
60	      });
61	    },
62	  };
63	}
