1	/**
2	 * Distortion effect using WaveShaperNode.
3	 * Three curve types: soft clip (tanh), hard clip, tube simulation.
4	 */
5	
6	import { createBaseEffect } from "./create-effect";
7	import type { EffectFactory, EffectParameterSchema } from "./types";
8	
9	const CURVE_SIZE = 4096;
10	
11	const PARAMS: readonly EffectParameterSchema[] = [
12	  { name: "Drive", key: "drive", min: 1, max: 100, default: 20, step: 1, unit: "" },
13	  { name: "Curve Type", key: "curveType", min: 0, max: 2, default: 0, step: 1, unit: "" },
14	  { name: "Mix", key: "mix", min: 0, max: 100, default: 50, step: 1, unit: "%" },
15	];
16	
17	function makeSoftClipCurve(drive: number): Float32Array {
18	  const curve = new Float32Array(CURVE_SIZE);
19	  const k = drive;
20	  for (let i = 0; i < CURVE_SIZE; i++) {
21	    const x = (i * 2) / CURVE_SIZE - 1;
22	    curve[i] = Math.tanh(k * x);
23	  }
24	  return curve;
25	}
26	
27	function makeHardClipCurve(drive: number): Float32Array {
28	  const curve = new Float32Array(CURVE_SIZE);
29	  const threshold = 1 / Math.max(drive, 1);
30	  for (let i = 0; i < CURVE_SIZE; i++) {
31	    const x = (i * 2) / CURVE_SIZE - 1;
32	    curve[i] = Math.max(-1, Math.min(1, x / threshold));
33	  }
34	  return curve;
35	}
36	
37	function makeTubeCurve(drive: number): Float32Array {
38	  const curve = new Float32Array(CURVE_SIZE);
39	  const k = drive * 2;
40	  for (let i = 0; i < CURVE_SIZE; i++) {
41	    const x = (i * 2) / CURVE_SIZE - 1;
42	    // Asymmetric tube-style clipping
43	    if (x >= 0) {
44	      curve[i] = 1 - Math.exp(-k * x);
45	    } else {
46	      curve[i] = -(1 - Math.exp(k * x));
47	    }
48	  }
49	  return curve;
50	}
51	
52	const curveGenerators = [makeSoftClipCurve, makeHardClipCurve, makeTubeCurve] as const;
53	
54	export function createDistortionFactory(): EffectFactory {
55	  return {
56	    definition: { id: "distortion", name: "Distortion", parameters: PARAMS },
57	    create(ctx, id) {
58	      let shaper: WaveShaperNode;
59	      let currentDrive = 20;
60	      let currentCurveType = 0;
61	
62	      function updateCurve(): void {
63	        if (!shaper) return;
64	        const gen = curveGenerators[currentCurveType] ?? makeSoftClipCurve;
65	        shaper.curve = gen(currentDrive);
66	      }
67	
68	      return createBaseEffect({
69	        ctx,
70	        id,
71	        typeId: "distortion",
72	        params: PARAMS,
73	        buildChain(inputNode, outputNode) {
74	          shaper = ctx.createWaveShaper();
75	          shaper.oversample = "4x";
76	          updateCurve();
77	          inputNode.connect(shaper);
78	          shaper.connect(outputNode);
79	        },
80	        applyParam(key, value, setMix) {
81	          switch (key) {
82	            case "drive":
83	              currentDrive = value;
84	              updateCurve();
85	              break;
86	            case "curveType":
87	              currentCurveType = Math.round(value);
88	              updateCurve();
89	              break;
90	            case "mix":
91	              setMix(value / 100);
92	              break;
93	          }
94	        },
95	      });
96	    },
97	  };
98	}
