29	/**
30	 * Creates a base effect instance with:
31	 * - Wet/dry split: input -> dryGain -> output, input -> [effect chain] -> wetGain -> output
32	 * - Bypass toggle (sets dry=1, wet=0)
33	 * - Parameter storage with clamping
34	 */
35	export function createBaseEffect(opts: CreateEffectOptions): EffectInstance {
36	  const { ctx, id, typeId, params, buildChain, applyParam } = opts;
37	
38	  const input = ctx.createGain();
39	  const output = ctx.createGain();
40	  const dryGain = ctx.createGain();
41	  const wetGain = ctx.createGain();
42	
43	  // Internal nodes for the effect chain
44	  const effectInput = ctx.createGain();
45	  const effectOutput = ctx.createGain();
46	
47	  // Dry path: input -> dryGain -> output
48	  input.connect(dryGain);
49	  dryGain.connect(output);
50	
51	  // Wet path: input -> effectInput -> [effect chain] -> effectOutput -> wetGain -> output
52	  input.connect(effectInput);
53	  buildChain(effectInput, effectOutput);
54	  effectOutput.connect(wetGain);
55	  wetGain.connect(output);
56	
57	  // Default: fully wet (no dry signal)
58	  dryGain.gain.value = 0;
59	  wetGain.gain.value = 1;
60	
61	  // Parameter storage
62	  const paramMap = new Map<string, { schema: EffectParameterSchema; value: number }>();
63	  for (const p of params) {
64	    paramMap.set(p.key, { schema: p, value: p.default });
65	  }
66	
67	  let bypassed = false;
68	  let mixLevel = 1; // 0 = fully dry, 1 = fully wet
69	
70	  function applyMix(): void {
71	    if (bypassed) {
72	      dryGain.gain.value = 1;
73	      wetGain.gain.value = 0;
74	    } else {
75	      dryGain.gain.value = 1 - mixLevel;
76	      wetGain.gain.value = mixLevel;
77	    }
78	  }
79	
80	  function setMix(wet: number): void {
81	    mixLevel = clamp(wet, 0, 1);
82	    applyMix();
83	  }
84	
85	  const instance: EffectInstance = {
86	    id,
87	    typeId,
88	    input,
89	    output,
90	    dryGain,
91	    wetGain,
92	    bypassed: false,
93	
94	    getParam(key: string): number {
95	      return paramMap.get(key)?.value ?? 0;
96	    },
97	
98	    setParam(key: string, value: number): void {
99	      const entry = paramMap.get(key);
100	      if (!entry) return;
101	      entry.value = clamp(value, entry.schema.min, entry.schema.max);
102	      applyParam(key, entry.value, setMix);
103	    },
104	
105	    setBypassed(b: boolean): void {
106	      bypassed = b;
107	      instance.bypassed = b;
108	      applyMix();
109	    },
110	
111	    setMix,
112	
113	    dispose(): void {
114	      input.disconnect();
115	      output.disconnect();
116	      dryGain.disconnect();
117	      wetGain.disconnect();
118	      effectInput.disconnect();
119	      effectOutput.disconnect();
120	    },
121	  };
122	
123	  // Initialize all params (deferred to after instance creation)
124	  for (const [key, entry] of paramMap) {
125	    applyParam(key, entry.value, setMix);
126	  }
127	
128	  return instance;
129	}
