1	/**
2	 * Insert chain manager for mixer channel strips.
3	 * Manages a serial chain of effect nodes between source and destination.
4	 * Re-wires the Web Audio graph when inserts are added/removed.
5	 */
6	
7	export type InsertEntry = {
8	  readonly id: string;
9	  readonly input: AudioNode;
10	  readonly output: AudioNode;
11	};
12	
13	export type InsertChain = {
14	  addInsert(id: string, input: AudioNode, output: AudioNode): void;
15	  removeInsert(id: string): void;
16	  getInserts(): readonly InsertEntry[];
17	  dispose(): void;
18	};
19	
20	export function createInsertChain(
21	  source: AudioNode,
22	  dest: AudioNode,
23	): InsertChain {
24	  const inserts: InsertEntry[] = [];
25	
26	  function rewire(): void {
27	    // Disconnect everything in the chain
28	    source.disconnect();
29	    for (const entry of inserts) {
30	      entry.output.disconnect();
31	    }
32	
33	    if (inserts.length === 0) {
34	      source.connect(dest);
35	      return;
36	    }
37	
38	    // source -> first insert input
39	    source.connect(inserts[0]!.input);
40	
41	    // Chain inserts: each output -> next input
42	    for (let i = 0; i < inserts.length - 1; i++) {
43	      inserts[i]!.output.connect(inserts[i + 1]!.input);
44	    }
45	
46	    // Last insert output -> dest
47	    inserts[inserts.length - 1]!.output.connect(dest);
48	  }
49	
50	  // Initial wiring: source -> dest
51	  source.connect(dest);
52	
53	  return {
54	    addInsert(id: string, input: AudioNode, output: AudioNode): void {
55	      inserts.push({ id, input, output });
56	      rewire();
57	    },
58	
59	    removeInsert(id: string): void {
60	      const idx = inserts.findIndex((e) => e.id === id);
61	      if (idx === -1) return;
62	      inserts.splice(idx, 1);
63	      rewire();
64	    },
65	
66	    getInserts(): readonly InsertEntry[] {
67	      return [...inserts];
68	    },
69	
70	    dispose(): void {
71	      source.disconnect();
72	      for (const entry of inserts) {
73	        entry.output.disconnect();
74	      }
75	      inserts.length = 0;
76	    },
77	  };
78	}
