2	 * Zustand store for effects rack state.
3	 * Per-track effect chain stored as serializable state.
4	 */
5	
6	import { create } from "zustand";
7	import type { EffectSlotState } from "./types";
8	
9	export type EffectsStore = {
10	  trackEffects: Record<string, readonly EffectSlotState[]>;
11	
12	  addEffect: (trackId: string, slot: EffectSlotState) => void;
13	  removeEffect: (trackId: string, effectId: string) => void;
14	  updateEffectParam: (
15	    trackId: string,
16	    effectId: string,
17	    key: string,
18	    value: number,
19	  ) => void;
20	  toggleBypass: (trackId: string, effectId: string) => void;
21	  removeTrackEffects: (trackId: string) => void;
22	  reorderEffect: (trackId: string, effectId: string, toIndex: number) => void;
23	  getTrackEffects: (trackId: string) => readonly EffectSlotState[];
24	};
25	
26	export const useEffectsStore = create<EffectsStore>()((set, get) => ({
27	  trackEffects: {},
28	
29	  addEffect(trackId, slot) {
30	    set((s) => {
31	      const existing = s.trackEffects[trackId] ?? [];
32	      return {
33	        trackEffects: {
34	          ...s.trackEffects,
35	          [trackId]: [...existing, slot],
36	        },
37	      };
38	    });
39	  },
40	
41	  removeEffect(trackId, effectId) {
42	    set((s) => {
43	      const existing = s.trackEffects[trackId];
44	      if (!existing) return s;
45	      const next = existing.filter((e) => e.id !== effectId);
46	      const trackEffects = { ...s.trackEffects };
47	      if (next.length === 0) {
48	        delete trackEffects[trackId];
49	      } else {
50	        trackEffects[trackId] = next;
51	      }
52	      return { trackEffects };
53	    });
54	  },
55	
56	  updateEffectParam(trackId, effectId, key, value) {
57	    set((s) => {
58	      const existing = s.trackEffects[trackId];
59	      if (!existing) return s;
60	      return {
61	        trackEffects: {
62	          ...s.trackEffects,
63	          [trackId]: existing.map((e) =>
64	            e.id === effectId
65	              ? { ...e, params: { ...e.params, [key]: value } }
66	              : e,
67	          ),
68	        },
69	      };
70	    });
71	  },
72	
73	  toggleBypass(trackId, effectId) {
74	    set((s) => {
75	      const existing = s.trackEffects[trackId];
76	      if (!existing) return s;
77	      return {
78	        trackEffects: {
79	          ...s.trackEffects,
80	          [trackId]: existing.map((e) =>
81	            e.id === effectId ? { ...e, bypassed: !e.bypassed } : e,
82	          ),
83	        },
84	      };
85	    });
86	  },
87	
88	  removeTrackEffects(trackId) {
89	    set((s) => {
90	      const trackEffects = { ...s.trackEffects };
91	      delete trackEffects[trackId];
92	      return { trackEffects };
93	    });
94	  },
95	
96	  reorderEffect(trackId, effectId, toIndex) {
97	    set((s) => {
98	      const existing = s.trackEffects[trackId];
99	      if (!existing) return s;
100	      const fromIndex = existing.findIndex((e) => e.id === effectId);
101	      if (fromIndex === -1) return s;
102	      const next = [...existing];
103	      const moved = next.splice(fromIndex, 1)[0];
104	      if (moved === undefined) return s;
105	      next.splice(toIndex, 0, moved);
106	      return {
107	        trackEffects: {
108	          ...s.trackEffects,
109	          [trackId]: next,
110	        },
111	      };
112	    });
113	  },
114	
115	  getTrackEffects(trackId) {
116	    return get().trackEffects[trackId] ?? [];
117	  },
118	}));
